import java.util.ArrayList;

public class Main {
    public static void main(String[] args) {

        // Create an ArrayList of student names
        ArrayList<String> roster = new ArrayList<>();
        roster.add("Rahul Sharma");
        roster.add("Priya Verma");
        roster.add("Amit Patel");
        roster.add("Sneha Iyer");
        roster.add("Vikram Singh");

        // Display the roster
        System.out.println("=== Current Roster ===" );
        for (int i = 0; i < roster.size(); i++) {
            System.out.printf("%d. %s%n", i + 1, roster.get(i));
        }

        // Add a student
        roster.add("Kavitha Nair");
        System.out.println("\nAdded: Kavitha Nair");
        System.out.println("Total students: " + roster.size());

        // Remove a student by name
        boolean removed = roster.remove("Amit Patel");
        System.out.println("Removed Amit: " + removed);

        // Search
        String search = "Sneha Iyer";
        int    idx    = roster.indexOf(search);
        System.out.println(search + " is at position: " + (idx + 1));

        // Filter: names starting with 'P'
        System.out.println("\n=== Names starting with P ===");
        for (String name : roster) {
            if (name.startsWith("P")) {
                System.out.println(name);
            }
        }
    }
}

